import { Outlet, Navigate, useLocation } from 'react-router-dom';
import { Sidebar } from './Sidebar';
import { useAuth } from '@/contexts/AuthContext';
import { Loader2 } from 'lucide-react';
import AIChatPanel from '@/components/AIChatPanel';
import { useState } from 'react';

interface AppLayoutProps {
    requireAuth?: boolean;
}

export function AppLayout({ requireAuth = true }: AppLayoutProps) {
    const { user, loading } = useAuth();
    const [sidebarOpen, setSidebarOpen] = useState(false);

    if (loading) {
        return (
            <div className="h-screen w-screen flex items-center justify-center bg-ch-black">
                <div className="flex flex-col items-center gap-3">
                    <Loader2 className="w-8 h-8 text-ch-orange animate-spin" />
                    <div className="flex flex-col items-center">
                        <span className="text-ch-white font-medium">Click.Hero</span>
                        <span className="text-ch-text-muted text-xs">Sincronizando seu ecossistema...</span>
                    </div>
                </div>
            </div>
        );
    }

    if (requireAuth && !user) {
        console.log('[AppLayout] No user found, redirecting to login');
        return <Navigate to="/login" replace />;
    }

    return (
        <div className="flex h-screen overflow-hidden bg-ch-black">
            <Sidebar isOpen={sidebarOpen} setIsOpen={setSidebarOpen} />
            <main className="flex-1 overflow-y-auto">
                <div className="animate-fade-in">
                    <Outlet />
                </div>
            </main>
            <AIChatPanel />
        </div>
    );
}

// ... keep existing code (AuthLayout)

// Auth layout for login/register pages
export function AuthLayout() {
    const { user, loading } = useAuth();

    // Show loading spinner while checking auth
    if (loading) {
        return (
            <div className="h-screen w-screen flex items-center justify-center bg-ch-black">
                <div className="flex flex-col items-center gap-3">
                    <Loader2 className="w-8 h-8 text-ch-orange animate-spin" />
                    <span className="text-ch-text-muted text-sm">Carregando...</span>
                </div>
            </div>
        );
    }

    const location = useLocation();
    const isLogin = location.pathname === '/login';

    if (user) {
        return <Navigate to="/dashboard" replace />;
    }

    if (isLogin) {
        return <Outlet />;
    }

    return (
        <div className="min-h-screen flex items-center justify-center bg-ch-black p-4">
            <div className="w-full max-w-md animate-fade-in">
                <Outlet />
            </div>
        </div>
    );
}

import {
  LayoutDashboard,
  BarChart2,
  Settings,
  HelpCircle,
  Menu,
  X,
  Target, // New icon for Campaigns
  Megaphone, // New icon for Ad Sets
  Image, // New icon for Creatives
  Users,
  LogOut,
  ChevronLeft,
  ChevronRight,
  Zap,
  Activity, // New icon for Activity
  Sparkles,
  Award,
  BookOpen, // New icon for Knowledge Base,
  LifeBuoy
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '@/contexts/AuthContext';
import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

interface SidebarProps {
  isOpen: boolean;
  setIsOpen: (isOpen: boolean) => void;
}

export function Sidebar({ isOpen, setIsOpen }: SidebarProps) {
  const navigate = useNavigate();
  const location = useLocation();
  const { signOut } = useAuth();
  const [isCollapsed, setIsCollapsed] = useState(false);

  // Sync mobile open state with collapse state on larger screens if needed, 
  // currently treating them as separate concerns.

  const menuItems = [
    {
      label: 'Geral',
      items: [
        { icon: LayoutDashboard, label: 'Visão Geral', path: '/' },
        { icon: Activity, label: 'Monitoramento', path: '/monitoramento' }, // Changed icon/label
      ]
    },
    {
      label: 'Gestão de Tráfego',
      items: [
        { icon: Target, label: 'Campanhas', path: '/campanhas' },
        { icon: Megaphone, label: 'Conjuntos', path: '/adsets' }, // Placeholder path
        { icon: Image, label: 'Criativos', path: '/criativos' },
      ]
    },
    {
      label: 'Inteligência',
      items: [
        { icon: Sparkles, label: 'Diagnósticos IA', path: '/diagnosticos' },
        { icon: Award, label: 'Auditorias', path: '/auditorias' },
      ]
    },
    {
      label: 'Sistema',
      items: [
         { icon: Users, label: 'Equipe', path: '/equipe' },
         { icon: Settings, label: 'Configurações', path: '/configuracoes' },
      ]
    }
  ];

  const handleSignOut = async () => {
    try {
      await signOut();
      navigate('/login');
    } catch (error) {
      console.error('Erro ao sair:', error);
    }
  };

  return (
    <>
      {/* Mobile Overlay */}
      <AnimatePresence>
        {isOpen && (
           <motion.div
             initial={{ opacity: 0 }}
             animate={{ opacity: 1 }}
             exit={{ opacity: 0 }}
             onClick={() => setIsOpen(false)}
             className="fixed inset-0 bg-black/60 backdrop-blur-sm z-40 md:hidden"
           />
        )}
      </AnimatePresence>

      {/* Sidebar Container */}
      <motion.aside
        className={cn(
          "fixed top-0 left-0 h-screen bg-[#0A0A0A] border-r border-white/5 z-50 flex flex-col transition-all duration-300 ease-in-out",
          isOpen ? "translate-x-0" : "-translate-x-full md:translate-x-0",
          isCollapsed ? "w-20" : "w-72"
        )}
      >
          {/* Logo Section */}
          <div className={cn("h-20 flex items-center px-6 border-b border-white/5 relative", isCollapsed ? "justify-center" : "justify-between")}>
             {!isCollapsed ? (
                <div className="flex items-center gap-2">
                   <div className="w-8 h-8 bg-ch-orange rounded-lg flex items-center justify-center">
                      <Zap className="w-5 h-5 text-black fill-current" />
                   </div>
                   <span className="font-bold text-xl tracking-tight text-white">Click.Hero</span>
                </div>
             ) : (
                <div className="w-10 h-10 bg-ch-orange rounded-xl flex items-center justify-center shadow-[0_0_15px_-3px_var(--ch-orange)]">
                   <Zap className="w-6 h-6 text-black fill-current" />
                </div>
             )}

             {/* Collapse Toggle (Desktop only) */}
             <button 
                onClick={() => setIsCollapsed(!isCollapsed)}
                className="hidden md:flex absolute -right-3 top-1/2 -translate-y-1/2 w-6 h-6 bg-ch-black-soft border border-white/10 rounded-full items-center justify-center text-ch-text-dimmed hover:text-white hover:bg-white/10 transition-colors"
              >
                  {isCollapsed ? <ChevronRight className="w-3 h-3" /> : <ChevronLeft className="w-3 h-3" />}
              </button>

              {/* Mobile Close Button */}
              <button onClick={() => setIsOpen(false)} className="md:hidden text-ch-text-dimmed hover:text-white">
                 <X className="w-6 h-6" />
              </button>
          </div>

          {/* Navigation Items */}
          <div className="flex-1 overflow-y-auto py-6 px-3 space-y-8 custom-scrollbar">
             {menuItems.map((group, index) => (
               <div key={index} className="space-y-2">
                 {!isCollapsed && (
                    <h3 className="px-4 text-[10px] font-black uppercase tracking-widest text-ch-text-dimmed/50 mb-2">
                      {group.label}
                    </h3>
                 )}
                 {group.items.map((item) => {
                   const isActive = location.pathname === item.path;
                   return (
                     <Button
                       key={item.path}
                       variant="ghost"
                       onClick={() => {
                         navigate(item.path);
                         setIsOpen(false);
                       }}
                       className={cn(
                         "w-full flex items-center gap-3 rounded-xl transition-all duration-200 group relative overflow-hidden",
                         isCollapsed ? "justify-center p-2 h-12" : "justify-start px-4 h-11",
                         isActive 
                           ? "bg-ch-orange/10 text-ch-orange shadow-[0_0_20px_-10px_var(--ch-orange)]" // Active State
                           : "text-ch-text-dimmed hover:text-white hover:bg-white/5" // Inactive State
                       )}
                     >
                       {isActive && (
                          <div className="absolute left-0 top-0 bottom-0 w-1 bg-ch-orange rounded-r-full" />
                       )}

                       <item.icon className={cn(
                         "transition-colors", 
                         isCollapsed ? "w-6 h-6" : "w-4 h-4",
                         isActive ? "text-ch-orange" : "text-ch-text-dimmed group-hover:text-white"
                        )} />

                       {!isCollapsed && (
                         <span className="text-sm font-bold tracking-wide uppercase">{item.label}</span>
                       )}

                       {/* Tooltip for collapsed state could go here */}
                     </Button>
                   );
                 })}
               </div>
             ))}
          </div>

          {/* User / Footer Section */}
          <div className="p-4 border-t border-white/5 bg-black/20">
             {!isCollapsed ? (
                <div className="flex items-center justify-between gap-3 p-3 rounded-xl bg-white/5 border border-white/5">
                   <div className="flex flex-col overflow-hidden">
                      <span className="text-xs font-bold text-white truncate">Admin User</span>
                      <span className="text-[10px] text-ch-text-dimmed truncate">admin@clickhero.com</span>
                   </div>
                   <Button variant="ghost" size="icon" onClick={handleSignOut} className="h-8 w-8 hover:bg-white/10 hover:text-rose-400 rounded-lg">
                      <LogOut className="w-4 h-4" />
                   </Button>
                </div>
             ) : (
                <Button variant="ghost" size="icon" onClick={handleSignOut} className="w-full h-10 hover:bg-rose-500/10 hover:text-rose-400 rounded-xl">
                   <LogOut className="w-5 h-5" />
                </Button>
             )}
          </div>
      </motion.aside>
    </>
  );
}

import { useState, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { useAuth } from '@/contexts/AuthContext';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';
import { Loader2, User } from 'lucide-react';

const profileSchema = z.object({
    first_name: z.string().min(2, 'Nome deve ter pelo menos 2 caracteres'),
    last_name: z.string().min(2, 'Sobrenome deve ter pelo menos 2 caracteres'),
    email: z.string().email('Email inválido').optional(), // Read-only mostly
});

type ProfileFormValues = z.infer<typeof profileSchema>;

export function ProfileForm() {
    const { user, refreshUser } = useAuth();
    const [isLoading, setIsLoading] = useState(false);

    const form = useForm<ProfileFormValues>({
        resolver: zodResolver(profileSchema),
        defaultValues: {
            first_name: '',
            last_name: '',
            email: '',
        },
    });

    useEffect(() => {
        if (user) {
            form.reset({
                first_name: user.first_name || '',
                last_name: user.last_name || '',
                email: user.email || '',
            });
        }
    }, [user, form]);

    const onSubmit = async (data: ProfileFormValues) => {
        if (!user) return;
        setIsLoading(true);
        try {
            const { error } = await supabase
                .from('users')
                .update({
                    first_name: data.first_name,
                    last_name: data.last_name,
                })
                .eq('id', user.id);

            if (error) throw error;

            await refreshUser();
            toast.success('Perfil atualizado com sucesso!');
        } catch (error) {
            console.error('Error updating profile:', error);
            toast.error('Erro ao atualizar perfil.');
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="space-y-6">
            <div>
                <h3 className="text-lg font-medium text-ch-white">Informações Pessoais</h3>
                <p className="text-sm text-ch-text-muted">Atualize suas informações de identificação.</p>
            </div>
            <div className="p-6 glass-card border-white/5 rounded-2xl">
                <Form {...form}>
                    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <FormField
                                control={form.control}
                                name="first_name"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel className="text-ch-text-dimmed">Nome</FormLabel>
                                        <FormControl>
                                            <div className="relative">
                                                <User className="absolute left-3 top-2.5 h-4 w-4 text-ch-text-muted" />
                                                <Input placeholder="Seu nome" className="pl-9 bg-white/5 border-white/10 text-ch-white" {...field} />
                                            </div>
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                            <FormField
                                control={form.control}
                                name="last_name"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel className="text-ch-text-dimmed">Sobrenome</FormLabel>
                                        <FormControl>
                                            <Input placeholder="Seu sobrenome" className="bg-white/5 border-white/10 text-ch-white" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                        </div>

                        <FormField
                            control={form.control}
                            name="email"
                            render={({ field }) => (
                                <FormItem>
                                    <FormLabel className="text-ch-text-dimmed">Email</FormLabel>
                                    <FormControl>
                                        <Input placeholder="seu@email.com" className="bg-white/5 border-white/10 text-ch-text-muted cursor-not-allowed" {...field} disabled />
                                    </FormControl>
                                    <FormDescription className="text-xs text-white/30">
                                        O email não pode ser alterado diretamente por questões de segurança.
                                    </FormDescription>
                                    <FormMessage />
                                </FormItem>
                            )}
                        />

                        <div className="flex justify-end">
                            <Button type="submit" disabled={isLoading} className="bg-ch-orange text-black hover:bg-ch-orange/90">
                                {isLoading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                                Salvar Alterações
                            </Button>
                        </div>
                    </form>
                </Form>
            </div>
        </div>
    );
}
